import React from "react";
import { useNavigate, useLocation } from "react-router-dom";

const Sidebar = () => {

  const navigate = useNavigate();

  const location = useLocation();

  const user = JSON.parse(localStorage.getItem("user"));



  // ======================================
  // LOGOUT
  // ======================================

  const logout = () => {

    localStorage.removeItem("token");

    localStorage.removeItem("user");

    navigate("/login");

  };



  // ======================================
  // MENU BASED ON ROLE
  // ======================================

  const freelancerMenu = [

    { name: "Dashboard", path: "/freelancer/dashboard" },

    { name: "Find Projects", path: "/freelancer/projects" },

    { name: "My Proposals", path: "/freelancer/proposals" },

    { name: "Profile", path: "/freelancer/profile" },

  ];



  const clientMenu = [

    { name: "Dashboard", path: "/client/dashboard" },

    { name: "Post Project", path: "/client/post-project" },

    { name: "My Projects", path: "/client/my-projects" },

    { name: "Freelancers", path: "/client/freelancers" },

  ];



  const adminMenu = [

    { name: "Dashboard", path: "/admin/dashboard" },

    { name: "Manage Users", path: "/admin/users" },

    { name: "Manage Projects", path: "/admin/projects" },

    { name: "Reports", path: "/admin/reports" },

  ];



  let menu = [];



  if (user?.role === "freelancer") menu = freelancerMenu;

  if (user?.role === "client") menu = clientMenu;

  if (user?.role === "admin") menu = adminMenu;



  return (

    <div className="w-64 h-screen bg-gray-900 text-white p-5 fixed">


      {/* LOGO */}

      <h1

        onClick={() => navigate("/")}

        className="text-2xl font-bold mb-8 cursor-pointer text-blue-400"

      >

        FreelanceHub

      </h1>



      {/* MENU */}

      <ul className="space-y-4">

        {menu.map((item, index) => (

          <li

            key={index}

            onClick={() => navigate(item.path)}

            className={`cursor-pointer p-2 rounded-lg hover:bg-gray-700

              ${location.pathname === item.path && "bg-blue-500"}`}

          >

            {item.name}

          </li>

        ))}

      </ul>



      {/* LOGOUT */}

      <button

        onClick={logout}

        className="absolute bottom-10 left-5 bg-red-500 hover:bg-red-600 px-4 py-2 rounded-lg w-52"

      >

        Logout

      </button>


    </div>

  );

};

export default Sidebar;
